/**
 * Lets Swift assert it links a compatible core and refuse on mismatch (ADR-0007).
 */
public struct Capabilities {
    public var bindingVersion: String
    public var coreVersion: String
    public var `protocol`: String
    public var ciphersuite: String
    public var storageFormatVersion: UInt32
    public var maxIdentity: UInt64
    public var maxKeyPackage: UInt64
    public var maxWelcome: UInt64
    public var maxEnvelope: UInt64
    public var maxPlaintext: UInt64

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(bindingVersion: String, coreVersion: String, `protocol`: String, ciphersuite: String, storageFormatVersion: UInt32, maxIdentity: UInt64, maxKeyPackage: UInt64, maxWelcome: UInt64, maxEnvelope: UInt64, maxPlaintext: UInt64) {
        self.bindingVersion = bindingVersion
        self.coreVersion = coreVersion
        self.`protocol` = `protocol`
        self.ciphersuite = ciphersuite
        self.storageFormatVersion = storageFormatVersion
        self.maxIdentity = maxIdentity
        self.maxKeyPackage = maxKeyPackage
        self.maxWelcome = maxWelcome
        self.maxEnvelope = maxEnvelope
        self.maxPlaintext = maxPlaintext
    }
}

#if compiler(>=6)
extension Capabilities: Sendable {}
#endif


extension Capabilities: Equatable, Hashable {
    public static func ==(lhs: Capabilities, rhs: Capabilities) -> Bool {
        if lhs.bindingVersion != rhs.bindingVersion {
            return false
        }
        if lhs.coreVersion != rhs.coreVersion {
            return false
        }
        if lhs.`protocol` != rhs.`protocol` {
            return false
        }
        if lhs.ciphersuite != rhs.ciphersuite {
            return false
        }
        if lhs.storageFormatVersion != rhs.storageFormatVersion {
            return false
        }
        if lhs.maxIdentity != rhs.maxIdentity {
            return false
        }
        if lhs.maxKeyPackage != rhs.maxKeyPackage {
            return false
        }
        if lhs.maxWelcome != rhs.maxWelcome {
            return false
        }
        if lhs.maxEnvelope != rhs.maxEnvelope {
            return false
        }
        if lhs.maxPlaintext != rhs.maxPlaintext {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(bindingVersion)
        hasher.combine(coreVersion)
        hasher.combine(`protocol`)
        hasher.combine(ciphersuite)
        hasher.combine(storageFormatVersion)
        hasher.combine(maxIdentity)
        hasher.combine(maxKeyPackage)
        hasher.combine(maxWelcome)
        hasher.combine(maxEnvelope)
        hasher.combine(maxPlaintext)
    }
}



