        if lhs.direction != rhs.direction {
            return false
        }
        if lhs.plaintext != rhs.plaintext {
            return false
        }
        if lhs.envelopeId != rhs.envelopeId {
            return false
        }
        if lhs.secretId != rhs.secretId {
