// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.

public enum InboundResult {
    
    case application(plaintext: Data
    )
    /**
     * A commit advanced group state; no user-visible content.
     */
    case stateAdvanced
    /**
     * At-least-once redelivery or a replayed secret id — a durable no-op.
     */
    case duplicate
    /**
     * Stored sealed; the body is NOT delivered here. Show a placeholder and reveal later via
     * [`MlsClient::begin_secret_reveal`].
     */
    case secretSealed(secretId: Data
    )
    /**
     * ADR-0015: another device revealed `secret_id`; this copy is consumed. Refresh any
     * placeholder to its tombstone.
     */
    case secretConsumedRemotely(secretId: Data
    )
    /**
     * ADR-0014 Slice 2c: store `K_r` keyed by the sender for future sealed sends.
     */
    case deliveryKeyGranted(keyR: Data
    )
    /**
     * #7: `count` past messages were appended to this device's log.
     */
    case historySynced(count: UInt64
    )
}


#if compiler(>=6)
extension InboundResult: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeInboundResult: FfiConverterRustBuffer {
    typealias SwiftType = InboundResult

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> InboundResult {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .application(plaintext: try FfiConverterData.read(from: &buf)
        )
        
        case 2: return .stateAdvanced
        
        case 3: return .duplicate
        
        case 4: return .secretSealed(secretId: try FfiConverterData.read(from: &buf)
        )
        
        case 5: return .secretConsumedRemotely(secretId: try FfiConverterData.read(from: &buf)
        )
        
        case 6: return .deliveryKeyGranted(keyR: try FfiConverterData.read(from: &buf)
        )
        
        case 7: return .historySynced(count: try FfiConverterUInt64.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: InboundResult, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .application(plaintext):
            writeInt(&buf, Int32(1))
            FfiConverterData.write(plaintext, into: &buf)
            
        
        case .stateAdvanced:
            writeInt(&buf, Int32(2))
        
        
        case .duplicate:
            writeInt(&buf, Int32(3))
        
        
        case let .secretSealed(secretId):
            writeInt(&buf, Int32(4))
            FfiConverterData.write(secretId, into: &buf)
            
        
        case let .secretConsumedRemotely(secretId):
            writeInt(&buf, Int32(5))
            FfiConverterData.write(secretId, into: &buf)
            
        
        case let .deliveryKeyGranted(keyR):
            writeInt(&buf, Int32(6))
            FfiConverterData.write(keyR, into: &buf)
            
        
        case let .historySynced(count):
            writeInt(&buf, Int32(7))
            FfiConverterUInt64.write(count, into: &buf)
            
        }
    }
}


